use std::collections::HashMap;

struct UrlEntry {
    original_url: String,
    short_code: String,
    visit_count: u64,
}

struct UrlShortener {
    urls: HashMap<String, UrlEntry>,      // short_code -> entry
    reverse: HashMap<String, String>,      // original_url -> short_code
    counter: u64,
}

impl UrlShortener {
    fn new() -> Self {
        UrlShortener {
            urls: HashMap::new(),
            reverse: HashMap::new(),
            counter: 0,
        }
    }

    fn generate_code(&mut self) -> String {
        self.counter += 1;
        format!("rs{}", self.counter)
    }

    fn is_valid_url(url: &str) -> bool {
        url.starts_with("http://") || url.starts_with("https://")
    }

    fn shorten(&mut self, url: &str) -> Result<String, String> {
        if !Self::is_valid_url(url) {
            return Err(format!("Invalid URL: must start with http:// or https://"));
        }

        // Check if URL already shortened
        if let Some(existing_code) = self.reverse.get(url) {
            return Ok(existing_code.clone());
        }

        let code = self.generate_code();
        let entry = UrlEntry {
            original_url: url.to_string(),
            short_code: code.clone(),
            visit_count: 0,
        };

        self.reverse.insert(url.to_string(), code.clone());
        self.urls.insert(code.clone(), entry);
        Ok(code)
    }

    fn resolve(&mut self, short_code: &str) -> Option<String> {
        if let Some(entry) = self.urls.get_mut(short_code) {
            entry.visit_count += 1;
            let url = entry.original_url.clone();
            println!("Resolved: {} -> {}", short_code, url);
            Some(url)
        } else {
            println!("Short code '{}' not found", short_code);
            None
        }
    }

    fn stats(&self) {
        println!("--- URL Shortener Stats ---");
        println!("{:<8} {:<6} {}", "Code", "Visits", "Original URL");
        println!("{}", "-".repeat(60));

        let mut entries: Vec<&UrlEntry> = self.urls.values().collect();
        entries.sort_by(|a, b| a.short_code.cmp(&b.short_code));

        for entry in entries {
            println!(
                "{:<8} {:<6} {}",
                entry.short_code, entry.visit_count, entry.original_url
            );
        }
        println!("Total URLs: {}", self.urls.len());
    }
}

fn main() {
    let mut shortener = UrlShortener::new();

    let urls = vec![
        "https://www.rust-lang.org/learn",
        "https://doc.rust-lang.org/book/",
        "https://crates.io/",
        "https://www.rust-lang.org/learn",  // duplicate
    ];

    for url in urls {
        match shortener.shorten(url) {
            Ok(code) => println!("Shortened: {} -> {}", url, code),
            Err(e) => println!("Error: {}", e),
        }
    }

    println!();
    shortener.resolve("rs1");
    shortener.resolve("rs1");
    shortener.resolve("rs2");

    println!();
    shortener.stats();
}
